diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index c0cf1a7db726..f693c05fec62 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3298,19 +3298,19 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
   if (Value *V = foldIsPowerOf2OrZero(RHS, LHS, IsAnd, Builder))
     return V;

-  // TODO: One of these directions is fine with logical and/or, the other could
-  // be supported by inserting freeze.
-  if (!IsLogical) {
-    // E.g. (icmp slt x, 0) | (icmp sgt x, n) --> icmp ugt x, n
-    // E.g. (icmp sge x, 0) & (icmp slt x, n) --> icmp ult x, n
-    if (Value *V = simplifyRangeCheck(LHS, RHS, /*Inverted=*/!IsAnd))
-      return V;
+  // Fold range checks like (x >= 0) && (x < n) -> x ult n
+  // and (x < 0) || (x >= n) -> x uge n.
+  // This is valid for both logical and bitwise operations.
+  // E.g. (icmp slt x, 0) | (icmp sgt x, n) --> icmp ugt x, n
+  // E.g. (icmp sge x, 0) & (icmp slt x, n) --> icmp ult x, n
+  if (Value *V = simplifyRangeCheck(LHS, RHS, /*Inverted=*/!IsAnd))
+    return V;
+
+  // E.g. (icmp sgt x, n) | (icmp slt x, 0) --> icmp ugt x, n
+  // E.g. (icmp slt x, n) & (icmp sge x, 0) --> icmp ult x, n
+  if (Value *V = simplifyRangeCheck(RHS, LHS, /*Inverted=*/!IsAnd))
+    return V;

-    // E.g. (icmp sgt x, n) | (icmp slt x, 0) --> icmp ugt x, n
-    // E.g. (icmp slt x, n) & (icmp sge x, 0) --> icmp ult x, n
-    if (Value *V = simplifyRangeCheck(RHS, LHS, /*Inverted=*/!IsAnd))
-      return V;
-  }

   // TODO: Add conjugated or fold, check whether it is safe for logical and/or.
   if (IsAnd && !IsLogical)
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 4d3de76389c2..ac4b9fc32d51 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3253,6 +3253,20 @@ Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
           return replaceInstUsesWith(SI, V);
   }

+  // Handle: select (select C, icmp1, false), icmp2, false
+  // which represents: C && icmp1 && icmp2
+  // Try to fold icmp1 && icmp2 using range check
+  if (match(FalseVal, m_Zero())) {
+    Value *C, *CondICmp;
+    if (match(CondVal, m_LogicalAnd(m_Value(C), m_Value(CondICmp)))) {
+      if (auto *ICmp0 = dyn_cast<ICmpInst>(CondICmp))
+        if (auto *ICmp1 = dyn_cast<ICmpInst>(TrueVal))
+          if (Value *V = simplifyRangeCheck(ICmp0, ICmp1, /*Inverted=*/false))
+            return SelectInst::Create(C, V, Zero);
+    }
+  }
+
+
   // select (a || b), c, false -> select a, c, false
   // select c, (a || b), false -> select c, a, false
   //   if c implies that b is false.

